def binarySearch(nums, target):
    left = 0
    right = len(nums) - 1

    while left <= right:
        mid = left + (right - left) // 2  # safe mid calculation

        if nums[mid] == target:
            return mid
        elif nums[mid] < target:
            left = mid + 1   # search right half
        else:
            right = mid - 1  # search left half

    return -1

